{"code": "import re
import math

clinical_data = env['data_1']
rna_data = env['data_2']

# Extract barcode from Patient_description
barcode_to_histology = {}
for row in clinical_data:
    desc = row['Patient_description']
    histology = row['icd_o_3_histology']
    if histology and not histology.startswith('['):
        match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', desc)
        if match:
            barcode = match.group(0)
            barcode_to_histology[barcode] = histology

# Map RNA data
histology_expressions = {}
for row in rna_data:
    barcode = row['ParticipantBarcode']
    count = row['normalized_count']
    if barcode in barcode_to_histology:
        histology = barcode_to_histology[barcode]
        log_expr = math.log10(count + 1)
        if histology not in histology_expressions:
            histology_expressions[histology] = []
        histology_expressions[histology].append(log_expr)

# Compute averages
results = {}
for histology, exprs in histology_expressions.items():
    avg = sum(exprs) / len(exprs)
    results[histology] = round(avg, 4)

print(results)
"}

